#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005

// Define the structure for a tree node
typedef struct Node {
    int data;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new tree node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->data = data;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to perform DFS traversal
int dfs(Node* root, int* nodes, int k) {
    if (root == NULL) return 0;
    int count = 0;
    for (int i = 0; i < k; i++) {
        if (root->data == nodes[i]) count++;
    }
    return count + dfs(root->left, nodes, k) + dfs(root->right, nodes, k);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        Node* root = NULL;
