#include <iostream>
#include <vector>
using namespace std;

// Define the structure for a tree node
struct Node {
    int data;
    vector<int> children;
};

// Function to perform DFS traversal
bool dfs(int node, vector<int>& nodes, vector<vector<int>>& tree) {
    if (node == -1) return true;
    bool found = false;
    for (int i = 0; i < nodes.size(); i++) {
        if (node + 1 == nodes[i]) {
            nodes.erase(nodes.begin() + i);
            found = true;
            break;
        }
    }
    if (found) {
        for (int child : tree[node]) {
            if (!dfs(child, nodes, tree)) return false;
        }
    }
    return nodes.empty();
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<vector<int>> tree(n);
        for (int i = 0; i < n - 1; i++) {
            int u, v;
            cin >> u >> v;
            tree[u - 1].push_back(v - 1);
            tree[v - 1].push_back(u - 1);
        }
        int q;
        cin >> q;
        while (q--) {
            int k;
            cin >> k;
            vector<int> nodes(k);
            for (int i = 0; i < k; i++) {
                cin >> nodes[i];
                nodes[i]--;
            }
            bool found = false;
            for (int i = 0; i < n; i++) {
                if (dfs(i, nodes, tree)) {
                    cout << "Yes" << endl;
                    found = true;
                    break;
                }
            }
            if (!found) cout << "No" << endl;
        }
    }
    return 0;
}

