    def __init__(self, data):
        self.data = data
        self.children = []

# Function to perform DFS traversal
def dfs(node, nodes):
    if node is None: return True
    found = False
    for i in range(len(nodes)):
        if node.data == nodes[i]:
            nodes.pop(i)
            found = True
            break
    if found:
        for child in node.children:
            if not dfs(child, nodes): return False
    return len(nodes) == 0

